mapper.update:
update t_org
set org_nm=#{orgNm}
,org_en=#{orgEn}
,head_nm=#{headNm}
,sido_cd=#{sidoCd}
,bsn_no=#{bsnNo}
,bank_nm=#{bankNm}
,bank_no=#{bankNo}
,bank_user_nm=#{bankUserNm}

where org_cd=#{orgCd}

update t_org
set use_check=#{useCheck},use_gooroomee=#{useGooroomee}, use_mov=#{useMov}

,jigin_file_nm=#{jiginFileNm},jigin_file_renm=#{jiginFileRenm}
,jigin_file_data=#{jiginFileData}


,bsn_file_nm=#{bsnFileNm},bsn_file_renm=#{bsnFileRenm}


,bank_file_nm=#{bankFileNm},bank_file_renm=#{bankFileRenm}

where org_cd=#{orgCd}

update t_lecture_time
set gooroomee_id=#{gooroomeeId}
where edu_seq=#{eduSeq} and time_seq = #{timeSeq}

update t_lecture_time
set 
	zoom_start_url=#{zoomStartUrl}
	, zoom_join_url = #{zoomJoinUrl}
	, zoom_id = #{zoomId}
where edu_seq=#{eduSeq} and time_seq = #{timeSeq}

update t_lecture_time
set 
	url=#{url}

	,url_pw=#{urlPw}

where edu_seq=#{eduSeq} and time_seq = #{timeSeq}

update t_lecture 
set check_yn=#{checkYn}
where edu_seq=#{eduSeq}

/** tableMapper.updatePayByPk */
update t_pay
set state=#{state}
,upd_dt=#{updDt}
where pay_no=#{payNo}

update t_sms
set result_cd=#{resultCd}
,result_msg=#{resultMsg}
where idx=#{idx}

update t_sms_log
set result_cd=#{resultCd}
,result_msg=#{resultMsg}
where idx=#{idx}

update t_sms_log
set result_cd=#{resultCd}
,result_msg=#{resultMsg}
where edu_seq=#{eduSeq} and user_id=#{userId} and result_cd=0

update t_cert_num
set cert_num=#{certNum}
where ctgry_seq = #{ctgrySeq} and "year" = #{year} and sub_seq = #{subSeq} and cert_mode = #{certMode}

mapper.insert:
INSERT INTO T_EMAIL_DATA ( EMAIL_KEY -- 숫자 11자리, 메시지 일련번호, 반드시 고유값, 중복시 발송실패, 시퀀스(시리얼번호사용) , SENT_DATE
, EMAIL_STATE -- 1:전송대기, 3:전송수집중(QUE 수집), 5:전송완료(결과대기), 6:결과처리 완료(결과회신) , RSLT_CODE
, EMAIL -- 수신번호(숫자형태의 문자, 11~12자리), [*][중요]반드시 휴대폰 번호 형식으로만 입력, 01X0000XXXX , CALLBACK -- 발신번호(숫자형태의 문자, 지역번호 필수), [*][중요]휴대폰번호 사용시에는 발신도용 해제 여부 필요, 스미싱 악용 방지용 '번호도용 차단서비스' 가입자는 해제 후 설정가능 합니다. , EMAIL_TEXT -- SMS: 90byte 까지 입력(줄바꿈은 '\n' 처리 1Byte 처리, 1Byte로 계산), LMS:2000 Byte 이하 , USER_ID -- etc , EMAIL_SUBJECT -- 생략가능, LMS에서만 사용 최대 30Byte 이하 한글(2Byte)로 계산, 줄바꿈은 '\n' 처리 1Byte 처리, 1Byte로 계산 ) VALUES ( EMAIL_KEY_SERIAL.NEXT_VALUE , #{sendDt}
, 5 , #{resultCd}
, #{toAddr} -- 수신번호(숫자형태의 문자, 11~12자리) , #{fromAddr} -- 발신번호(숫자형태의 문자, 지역번호 필수) , #{text} , #{userId} , '이메일발송' )
